#include <bits/stdc++.h>
#define ull unsigned long long
#define mk(x,y) make_pair(x,y)
#define PII pair<int,int>
#define NoAns puts("-1");
#define FOR(i,j,k) for(int i=(j);i<=(k);++i)
#define ROF(i,j,k) for(int i=(j);i>=(k);--i)
#define FOI(a,b) for(auto a : b)
#define Yes puts("Yes");
#define No puts("No");
#define llinf 0x3f3f3f3f3f3f3f3f
#define inf 0x3f3f3f3f
#define ll long long
#define snd second
#define fst first
#define il inline
#define pb(x) push_back(x)
#define CI const int
#define cl(x) memset(x,0,sizeof x)
#define cli(x) memset(x,0x3f,sizeof x)
#define lowbit(x) (x&(-x))
#define wh(x) while(x)
#define gc() getchar()
#define pc(x) putchar(x)
#define NP namespace
using NP std;
il ll read()
{
    ll x=0,f=1;char ch=gc();
    wh(ch<'0'||ch>'9'){if(ch=='-')f=-1;ch=getchar();}
    wh(ch>='0'&&ch<='9'){x=x*10+ch-'0';ch=gc();}
    return x*f;
}
void write(ll x)
{
    if(x<0)pc('-'),x=-x;
    if(x>9)write(x/10);
    pc(x%10+'0');
}
void writeln(ll x)
{
    write(x);
    puts("");
    return;
}
CI MAXN=1e2+5;
struct Node
{
	int t,f,h;
}a[MAXN];
int d, g, f[MAXN];
bool cmp(Node a, Node b){return a.t < b.t;}
int main(void)
{
    d=read(),g=read();
	f[0]=10;
	FOR(i,1,g)
        a[i].t=read(),a[i].f=read(),a[i].h=read();
	sort(a+1,a+1+g,cmp);
	FOR(i,1,g)
	{
		ROF(j,d,0)
		{
			if(f[j]>=a[i].t)
			{
				if(j+a[i].h>=d)f[d]=max(f[d], f[j]);
				else f[j+a[i].h]=max(f[j + a[i].h], f[j]);
				f[j]=max(f[j],f[j]+a[i].f);
			}
		}
		if(f[d]!=0)
		{
            write(a[i].t);
			exit(false);
		}
	}
	write(f[0]);
	return false;
}
